const cfg = $('Config').first().json;
const apiKey = String(cfg.openwebuiApiKey || '').trim();
const jwtToken = String(cfg.openwebuiToken || '').trim();
const authToken = apiKey || jwtToken;

if (!authToken || authToken.includes('COLE_AQUI')) {
  throw new Error('Defina openwebuiApiKey ou openwebuiToken (JWT) no node Config.');
}

const payload = $json || {};
const detail = String(payload.detail || '').toLowerCase();
if (detail.includes('unauthorized') || detail.includes('not authenticated')) {
  throw new Error('Open WebUI retornou 401 Unauthorized. Atualize a API key ou o token JWT no node Config.');
}

const rawModels = Array.isArray(payload)
  ? payload
  : (payload.data || payload.models || payload.items || payload.results || []);

if (!Array.isArray(rawModels)) {
  throw new Error('Resposta inesperada da API de modelos do Open WebUI.');
}

const normalized = rawModels.map((m) => ({
  id: m.id ?? m.model ?? m.name ?? '',
  name: m.name ?? m.id ?? m.model ?? '',
  owner: m.owned_by ?? m.source ?? '',
  raw: m
}));

const prefix = String(cfg.agentPrefix || '').trim();
let agents = [];

if (!prefix) {
  agents = normalized;
} else {
  agents = normalized.filter((m) =>
    String(m.id).startsWith(prefix) || String(m.name).startsWith(prefix)
  );

  if (agents.length === 0 && normalized.length > 0) {
    agents = normalized;
  }
}

return [{
  json: {
    openwebuiBaseUrl: cfg.openwebuiBaseUrl,
    openwebuiApiKey: apiKey,
    openwebuiToken: jwtToken,
    qdrantUrl: cfg.qdrantUrl,
    agentPrefix: cfg.agentPrefix ?? '',
    modelsCount: normalized.length,
    agentsCount: agents.length,
    models: normalized,
    agents,
    agentPrefixUsed: prefix || '(vazio)'
  }
}];

const cfg = $('Normalizar Modelos/Agentes').first().json;
const payload = $json;
const rawChats = Array.isArray(payload)
  ? payload
  : (payload.data || payload.items || payload.results || []);

const chats = rawChats.map((c) => ({
  id: c.id ?? c.chat_id ?? '',
  title: c.title ?? c.name ?? '(sem titulo)',
  updatedAt: c.updated_at ?? c.updatedAt ?? null,
  model: c.model ?? c.model_id ?? null
}));

return [{
  json: {
    openwebuiBaseUrl: cfg.openwebuiBaseUrl,
    openwebuiApiKey: cfg.openwebuiApiKey,
    openwebuiToken: cfg.openwebuiToken,
    qdrantUrl: cfg.qdrantUrl,
    agentPrefix: cfg.agentPrefix ?? '',
    chatsCount: chats.length,
    chats
  }
}];

const modelsData = $('Normalizar Modelos/Agentes').first().json;
const chatsData = $('Normalizar Chats').first().json;

const payload = $json || {};
const collections = payload?.result?.collections || payload?.collections || [];
const qdrantCollections = collections.map((c) => c.name || c.collection_name || JSON.stringify(c));

return [{
  json: {
    resumo: {
      totalModelos: modelsData.modelsCount,
      totalAgentesPorPrefixo: modelsData.agentsCount,
      totalChats: chatsData.chatsCount,
      totalColecoesQdrant: qdrantCollections.length
    },
    agentes: modelsData.agents,
    modelos: modelsData.models,
    chats: chatsData.chats,
    qdrantCollections
  }
}];
